SELECT h.*, ste.site_nm AS site_nm, prd.prod_nm AS prod_nm, cd_sct.code_label AS chg_type_cd_nm FROM pdh_prod_sku_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN pd_prod prd ON prd.prod_id = h.prod_id LEFT JOIN sy_code cd_sct ON cd_sct.code_grp = 'SKU_CHG_TYPE' AND cd_sct.code_value = h.chg_type_cd
ORDER BY h.hist_id ASC ORDER BY h.hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

